#include "omp.h"
void main()
{
    int i=0, n=100;
    #pragma omp parallel
    {
        #pragma omp single
        printf("Hola mundo %d\n", i++);
        #pragma omp for
        for(i=0; i<n; i++){
            printf("Hola mundo %d", i);
        }
    }
}
```

